import React, { useState, useEffect, useRef } from 'react';
import './ChatInterface.css';
import ResourceCard from './ResourceCard';
import { sendMessage } from '../services/api';

function ChatInterface({ language, onLanguageChange, state, safeWord, sessionId, setSessionId, setCaseData }) {
  const [messages, setMessages] = useState([]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [resources, setResources] = useState([]);
  const [showDecoy, setShowDecoy] = useState(false);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);

  // Generate session ID on mount
  useEffect(() => {
    if (!sessionId) {
      const newSessionId = 'SAH-SESS-' + Math.random().toString(36).substr(2, 6).toUpperCase();
      setSessionId(newSessionId);
    }
  }, [sessionId, setSessionId]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || isLoading) return;

    const messageText = inputValue.trim();
    
    // Check for safe word
    if (safeWord && messageText.toLowerCase().includes(safeWord.toLowerCase())) {
      setShowDecoy(true);
      setTimeout(() => setShowDecoy(false), 5000); // Auto-hide after 5 seconds
      setInputValue('');
      return;
    }

    setInputValue('');

    // Add user message
    const userMessage = {
      id: Date.now(),
      text: messageText,
      sender: 'user',
      timestamp: new Date()
    };
    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    try {
      const response = await sendMessage(messageText, language, state);

      // Add system response
      const systemMessage = {
        id: Date.now() + 1,
        text: response.response,
        sender: 'system',
        timestamp: new Date(),
        crisisType: response.crisisType,
        severityLevel: response.severityLevel
      };
      setMessages(prev => [...prev, systemMessage]);

      // Update resources
      if (response.resources) {
        setResources(response.resources);
      }

      // Store case data for result page
      if (response.crisisType && setCaseData) {
        setCaseData({
          crisisType: response.crisisType,
          severity: response.severityLevel,
          sessionId: sessionId
        });
      }
    } catch (error) {
      console.error('Error sending message:', error);
      const errorMessage = {
        id: Date.now() + 1,
        text: language === 'en'
          ? 'Sorry, I encountered an error. Please try again.'
          : 'क्षमा करें, मुझे एक त्रुटि का सामना करना पड़ा। कृपया पुन: प्रयास करें।',
        sender: 'system',
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
      inputRef.current?.focus();
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const formatTime = (date) => {
    return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
  };

  const getCrisisTypeLabel = (type) => {
    const labels = {
      en: {
        harassment: 'Harassment',
        ragging: 'Ragging',
        cyberbullying: 'Cyberbullying',
        mental_health: 'Mental Health',
        self_harm: 'Self-Harm',
        physical_threat: 'Physical Threat'
      },
      hi: {
        harassment: 'उत्पीड़न',
        ragging: 'रैगिंग',
        cyberbullying: 'साइबरबुलिंग',
        mental_health: 'मानसिक स्वास्थ्य',
        self_harm: 'आत्म-हानि',
        physical_threat: 'शारीरिक खतरा'
      }
    };
    return labels[language][type] || type;
  };

  const getStateLabel = () => {
    const states = {
      MH: { en: 'Maharashtra', hi: 'महाराष्ट्र' },
      DL: { en: 'Delhi', hi: 'दिल्ली' },
      TN: { en: 'Tamil Nadu', hi: 'तमिलनाडु' },
      KA: { en: 'Karnataka', hi: 'कर्नाटक' },
      WB: { en: 'West Bengal', hi: 'पश्चिम बंगाल' }
    };
    return states[state]?.[language] || state;
  };

  if (showDecoy) {
    return (
      <div className="decoy-screen">
        <div className="decoy-content">
          <h1>Computer Science Notes - Data Structures</h1>
          <p className="decoy-date">March 1, 2026</p>
          <h3>Topics Covered:</h3>
          <ul>
            <li>Arrays and Linked Lists</li>
            <li>Stack and Queue Implementation</li>
            <li>Binary Search Trees</li>
            <li>Hash Tables and Collision Resolution</li>
          </ul>
          <div className="decoy-notes">
            <strong>Notes:</strong>
            <p>Remember to review sorting algorithms for the upcoming exam. Focus on time complexity analysis.</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="chat-interface">
      {/* Header */}
      <div className="chat-header">
        <div className="header-left">
          <button className="back-button" onClick={onBack}>
            <svg viewBox="0 0 24 24" fill="none">
              <path d="M19 12H5M5 12L12 19M5 12L12 5" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </button>
          <div className="header-title">
            <h2>{language === 'en' ? 'AI First Responder' : 'AI फर्स्ट रेस्पॉन्डर'}</h2>
            <span className="header-subtitle">
              {language === 'en' ? 'Safe & Confidential' : 'सुरक्षित और गोपनीय'}
            </span>
          </div>
        </div>
        <div className="header-right">
          <div className="language-toggle-mini">
            <button
              className={`lang-btn-mini ${language === 'en' ? 'active' : ''}`}
              onClick={() => onLanguageChange('en')}
            >
              EN
            </button>
            <button
              className={`lang-btn-mini ${language === 'hi' ? 'active' : ''}`}
              onClick={() => onLanguageChange('hi')}
            >
              हिं
            </button>
          </div>
          <div className="status-indicator">
            <span className="status-dot"></span>
            {language === 'en' ? 'Online' : 'ऑनलाइन'}
          </div>
        </div>
      </div>

      {/* Chat Container */}
      <div className="chat-container">
        <div className="messages-area">
          {messages.length === 0 ? (
            <div className="empty-state">
              <div className="empty-state-icon">
                <svg viewBox="0 0 24 24" fill="none">
                  <path d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" strokeLinecap="round" strokeLinejoin="round" />
                </svg>
              </div>
              <h3>{language === 'en' ? 'How can I help you today?' : 'आज मैं आपकी कैसे मदद कर सकता हूं?'}</h3>
              <p>
                {language === 'en'
                  ? 'Share your concerns safely. I\'m here to listen and guide you to the right support.'
                  : 'अपनी चिंताओं को सुरक्षित रूप से साझा करें। मैं सुनने और सही सहायता के लिए मार्गदर्शन करने के लिए यहां हूं।'}
              </p>
            </div>
          ) : (
            <>
              {messages.map((message) => (
                <div key={message.id} className={`message-bubble ${message.sender}`}>
                  <div className="message-avatar">
                    {message.sender === 'user' ? (
                      <svg viewBox="0 0 24 24" fill="none">
                        <path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeLinecap="round" strokeLinejoin="round" />
                      </svg>
                    ) : (
                      <svg viewBox="0 0 24 24" fill="none">
                        <path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" strokeLinecap="round" strokeLinejoin="round" />
                      </svg>
                    )}
                  </div>
                  <div className="message-content">
                    <div className="message-text">{message.text}</div>
                    {message.crisisType && (
                      <div className={`crisis-badge severity-${message.severityLevel}`}>
                        {getCrisisTypeLabel(message.crisisType)} • Level {message.severityLevel}
                      </div>
                    )}
                    <span className="message-time">{formatTime(message.timestamp)}</span>
                  </div>
                </div>
              ))}
              {isLoading && (
                <div className="message-bubble system">
                  <div className="message-avatar">
                    <svg viewBox="0 0 24 24" fill="none">
                      <path d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" strokeLinecap="round" strokeLinejoin="round" />
                    </svg>
                  </div>
                  <div className="typing-indicator">
                    <div className="typing-dot"></div>
                    <div className="typing-dot"></div>
                    <div className="typing-dot"></div>
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </>
          )}
        </div>

        {/* Resources Section */}
        {resources.length > 0 && (
          <div className="resources-section">
            <h3>
              <svg viewBox="0 0 24 24" fill="none">
                <path d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
              {language === 'en' ? 'Recommended Support Resources' : 'अनुशंसित सहायता संसाधन'}
            </h3>
            <div className="resources-grid">
              {resources.map((resource, index) => (
                <ResourceCard key={index} resource={resource} language={language} />
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="input-area">
        <div className="input-container">
          <div className="input-wrapper">
            <textarea
              ref={inputRef}
              className="message-input"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder={language === 'en' ? 'Type your message...' : 'अपना संदेश टाइप करें...'}
              rows="1"
              disabled={isLoading}
            />
            <button className="voice-button" title={language === 'en' ? 'Voice input' : 'आवाज इनपुट'}>
              <svg viewBox="0 0 24 24" fill="none">
                <path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
            </button>
          </div>
          <button
            className="send-button"
            onClick={handleSendMessage}
            disabled={!inputValue.trim() || isLoading}
            title={language === 'en' ? 'Send message' : 'संदेश भेजें'}
          >
            <svg viewBox="0 0 24 24" fill="none">
              <path d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
}

export default ChatInterface;
